  1	import React from 'react';
  2	import {
  3	  Select,
  4	  SelectList,
  5	  SelectOption,
  6	  SelectOptionProps,
  7	  SelectProps,
  8	} from '@patternfly/react-core/dist/esm/components/Select';
  9	import {
 10	  MenuToggle,
 11	  MenuToggleElement,
 12	  MenuToggleProps,
 13	} from '@patternfly/react-core/dist/esm/components/MenuToggle';
 14	
 15	export interface SimpleSelectOption extends Omit<SelectOptionProps, 'content'> {
 16	  /** Content of the select option. */
 17	  content: React.ReactNode;
 18	  /** Value of the select option. */
 19	  value: string | number;
 20	}
 21	
 22	export interface SimpleSelectProps extends Omit<SelectProps, 'toggle'> {
 23	  /** @hide Forwarded ref */
 24	  innerRef?: React.Ref<any>;
 25	  /** Initial options of the select. */
 26	  initialOptions?: SimpleSelectOption[];
 27	  /** Callback triggered on selection. */
 28	  onSelect?: (_event: React.MouseEvent<Element, MouseEvent>, selection: string | number) => void;
 29	  /** Callback triggered when the select opens or closes. */
 30	  onToggle?: (nextIsOpen: boolean) => void;
 31	  /** Flag indicating the select should be disabled. */
 32	  isDisabled?: boolean;
 33	  /** Content of the toggle. Defaults to the selected option. */
 34	  toggleContent?: React.ReactNode;
 35	  /** Placeholder text for the select input. */
 36	  placeholder?: string;
 37	  /** Width of the toggle. */
 38	  toggleWidth?: string;
 39	  /** Additional props passed to the toggle. */
 40	  toggleProps?: MenuToggleProps;
 41	}
 42	
 43	const SimpleSelectBase: React.FunctionComponent<SimpleSelectProps> = ({
 44	  id,
 45	  innerRef,
 46	  initialOptions,
 47	  isDisabled,
 48	  onSelect,
 49	  onToggle,
 50	  toggleContent,
 51	  toggleWidth = '200px',
 52	  toggleProps,
 53	  placeholder = 'Select a value',
 54	  ...props
 55	}: SimpleSelectProps) => {
 56	  const [isOpen, setIsOpen] = React.useState(false);
 57	  const [selected, setSelected] = React.useState<SimpleSelectOption | undefined>();
 58	
 59	  React.useEffect(() => {
 60	    const selectedOption = initialOptions?.find((option) => option.selected);
 61	    setSelected(selectedOption);
 62	  }, [initialOptions]);
 63	
 64	  const simpleSelectOptions = initialOptions?.map((option) => {
 65	    const { content, value, ...props } = option;
 66	    const isSelected = selected?.value === value;
 67	    return (
 68	      <SelectOption value={value} key={value} isSelected={isSelected} {...props}>
 69	        {content}
 70	      </SelectOption>
 71	    );
 72	  });
 73	
 74	  const onToggleClick = () => {
 75	    onToggle && onToggle(!isOpen);
 76	    setIsOpen(!isOpen);
 77	  };
 78	
 79	  const _onSelect = (
 80	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
 81	    value: string | number | undefined,
 82	  ) => {
 83	    onSelect && onSelect(_event, value);
 84	    setSelected(initialOptions.find((o) => o.value === value));
 85	    onToggle && onToggle(true);
 86	    setIsOpen(false);
 87	  };
 88	
 89	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
 90	    <MenuToggle
 91	      id={`${id}-dropdown`}
 92	      ref={toggleRef}
 93	      onClick={onToggleClick}
 94	      isExpanded={isOpen}
 95	      isDisabled={isDisabled}
 96	      style={
 97	        {
 98	          width: toggleWidth,
 99	        } as React.CSSProperties
100	      }
101	      {...toggleProps}
102	    >
103	      {toggleContent ? toggleContent : selected?.content || placeholder}
104	    </MenuToggle>
105	  );
106	
107	  return (
108	    <Select
109	      isOpen={isOpen}
110	      selected={selected}
111	      onSelect={_onSelect}
112	      onOpenChange={(isOpen) => {
113	        onToggle && onToggle(isOpen);
114	        setIsOpen(isOpen);
115	      }}
116	      toggle={toggle}
117	      shouldFocusToggleOnSelect
118	      ref={innerRef}
119	      {...props}
120	    >
121	      <SelectList>{simpleSelectOptions}</SelectList>
122	    </Select>
123	  );
124	};
125	
126	export const SimpleSelect = React.forwardRef((props: SimpleSelectProps, ref: React.Ref<any>) => (
127	  <SimpleSelectBase {...props} innerRef={ref} />
128	));
129	
130	SimpleSelect.displayName = 'SimpleSelect';

